import { readdirSync, existsSync, writeFileSync } from 'node:fs'
import { join } from 'node:path'

// AUTO-GENERATED target: src/data/preActivityGalleries.ts
// Run: node scripts/build-pre-activity-galleries.mjs

const WEB = /\.(jpe?g|png)$/i
const natural = (a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })

// Maps event id (slug) → folder name under public/
// Folders use the event title with spaces/& exactly as-is
const EVENTS = {
  'startup-idea-fest': 'Startup & Idea Fest',
  'mentoring-session': 'Mentoring Session',
  'bootcamp':          'Bootcamp',
  'tv-show':           'Television Show',
  'public-voting':     'Public Online Voting',
  'industry-visit':    'Industry & Field Visit',
  'speed-dating':      'Speed Dating',
  'province-meetup':   'Province Meetup',
}

const entries = Object.entries(EVENTS).map(([id, folder]) => {
  const dir = join('public', folder)
  if (!existsSync(dir)) {
    return `  ${JSON.stringify(id)}: [],`
  }
  const files = readdirSync(dir)
    .filter(f => WEB.test(f))
    .sort(natural)
    .map(f => `    ${JSON.stringify(`/${folder}/${f}`)},`)
    .join('\n')
  return `  ${JSON.stringify(id)}: [\n${files}\n  ],`
})

writeFileSync(
  'src/data/preActivityGalleries.ts',
  `// AUTO-GENERATED by scripts/build-pre-activity-galleries.mjs — do not edit by hand.
// Regenerate after adding/removing photos: node scripts/build-pre-activity-galleries.mjs
export const PRE_ACTIVITY_GALLERIES: Record<string, string[]> = {
${entries.join('\n')}
}
`
)
console.log('Wrote src/data/preActivityGalleries.ts')
